/// |           _msg_type            |                                                                                                                                                                                                                                            username                                                                                                                                                                                                                                            |
/// +---+---+---+---+---+---+---+---+---+---+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+----+-----+-----+-----+-----+
///
///  Field      Bits   Offset     Description
///  _msg_type   8     byte 0:0   ClientMessage::Name
///  username   96     byte 1:0   Player name (12 bytes)
use deku::{DekuRead, DekuWrite};

use crate::protocol::ClientMessage;

#[derive(Debug, Clone, Copy, DekuRead, DekuWrite)]
pub struct Name {
    _msg_type: u8,

    pub username: [u8; 12],
}

impl Name {
    /// Creates a name broadcast message with a 12-byte username buffer.
    pub fn new(username: [u8; 12]) -> Self {
        Self {
            _msg_type: ClientMessage::Name as u8,
            username,
        }
    }
}
